import base64, os, subprocess, sys, shutil
from pathlib import Path

# --- 1. Install dependencies ---
subprocess.run([sys.executable, '-m', 'pip', 'install', '-q',
    'fastapi', 'uvicorn', 'python-multipart', 'gdown',
    'openai-whisper', 'pyngrok', 'nest-asyncio'], check=True)

subprocess.run(['ffmpeg', '-version'], capture_output=True, check=True)
print('FFmpeg OK')

# --- 2. Create directory structure ---
BASE = Path("/kaggle/working/project")
for d in ("frontend","downloads","transcript","scene_json",
          "screenshots","output","temp"):
    (BASE / d).mkdir(parents=True, exist_ok=True)

# --- 3. Write source files (base64) ---
FILES = {
    'app.py': '',
    'frontend/style.css': '',
    'frontend/script.js': '',
    'frontend/index.html': '',
}

for relpath, b64data in FILES.items():
    (BASE / relpath).write_bytes(base64.b64decode(b64data))
print('Source files written.')

# --- 4. Set Ngrok auth token ---
from pyngrok import ngrok

# >>> PASTE YOUR NGROK AUTH TOKEN HERE <<<
NGROK_AUTH_TOKEN = ''

if NGROK_AUTH_TOKEN:
    ngrok.set_auth_token(NGROK_AUTH_TOKEN)
    print('Ngrok token set.')
else:
    print('WARNING: Set NGROK_AUTH_TOKEN above.')

# --- 5. Start server ---
os.chdir(str(BASE))
sys.path.insert(0, str(BASE))

import uvicorn, nest_asyncio
tunnel = ngrok.connect(8000)
print('='*60)
print(f'  PUBLIC URL: {tunnel.public_url}')
print('='*60)

nest_asyncio.apply()
uvicorn.run('app:app', host='0.0.0.0', port=8000,
          timeout_keep_alive=1200, log_level='info')

